// 性能优化版本
const sapData = $('判断SAP是否成功返回数据').first().json.batches[0].data;

// 1. 使用Map建立索引（性能关键点）
const materialCodeMap = new Map();
if (Array.isArray(sapData)) {
  sapData.forEach(item => {
    if (item?.PLNBEZ) {
      const code = item.PLNBEZ;
      if (!materialCodeMap.has(code)) {
        materialCodeMap.set(code, []);
      }
      materialCodeMap.get(code).push(item);
    }
  });
}

// 2. 批量处理输入数据
return $input.all().map(item => {
  const children = materialCodeMap.get(item.json.material_code) || [];
  return {
    json: {
      ...item.json,
      children: children.slice(0, 1000) // 限制最大数量防止内存爆炸
    }
  };
});

