const orderList = $("Aggregate1").all()[0].json.orderList;
const inputItems = $input.all();

// 创建物料代码映射用于快速查找
const inputMaterialMap = {};
for (const item of inputItems) {
    inputMaterialMap[item.json.work_order_number] = item; // 存储整个对象以便引用
}

// 处理现有数据并添加新数据
const result = [...inputItems]; // 复制原始输入

for (const item of inputItems) {
    const order = orderList.find(e => e.order_number === item.json.work_order_number);

    if (order) {
        // 使用严格比较并处理可能的null/undefined
        const isSameDesc = order.material_description === item.json.material_description;
        const isSameQty = Number(order.production_quantity) === Number(item.json.production_quantity);
        const isSameStart = order.production_date === item.json.production_date;
        const isSameEnd = order.production_end_date === item.json.production_end_date;
        const isSameZecnl4 = String(order.zecnl4 || '') === String(item.json.zecnl4 || '');

        if (isSameDesc && isSameQty && isSameStart && isSameEnd && isSameZecnl4) {
            item.json.is_update = 0; // 没有变化
        } else {
            // 用新数据覆盖旧数据（包括zecnl4）
            item.json.material_description = order.material_description;
            item.json.production_quantity = order.production_quantity;
            item.json.production_date = order.production_date;
            item.json.production_end_date = order.production_end_date;
            item.json.zecnl4 = order.zecnl4; // 确保更新这个字段
            item.json.is_update = 1; // 标记为已更新

            console.log('更新记录:', {
                work_order: order.order_number,
                old_zecnl4: inputMaterialMap[order.order_number].json.zecnl4,
                new_zecnl4: order.zecnl4
            });
        }
    } else {
        item.json.is_update = 0;
    }
}

// 添加新数据（存在于orderList但不存在于input）
for (const order of orderList) {
    if (!inputMaterialMap[order.order_number]) {
        result.push({
            json: {
                material_code: order.material_code,
                material_description: order.material_description,
                base_bom_code: order.base_bom_code,
                type: order.type,
                order_status: order.order_status,
                work_order_number: order.order_number,
                order_create_time: order.order_create_time,
                production_quantity: order.production_quantity,
                production_date: order.production_date,
                production_end_date: order.production_end_date,
                zecnl4: order.zecnl4, // 确保包含此字段
                is_update: 1 // 新数据标记为需要更新
            }
        });
    }
}

return result;

