// 使用流式处理替代全量合并
let allSuccess = true;
let errorMessages = [];
let processedCount = 0;
let batchSize = 100; // 每批处理100条记录
let outputBatches = [];

try {
    // 分批次处理数据
    for (let i = 0; i < items.length; i += batchSize) {
        const batch = items.slice(i, i + batchSize);
        let batchResults = [];

        for (const item of batch) {
            processedCount++;

            // 检查数据有效性
            if (!item?.json?.ET_OUTPUT) {
                allSuccess = false;
                errorMessages.push(`Item ${processedCount} missing ET_OUTPUT`);
                continue;
            }

            if (item.json.E_TYPE !== "S") {
                allSuccess = false;
                errorMessages.push(`Item ${processedCount} has E_TYPE=${item.json.E_TYPE}`);
                continue;
            }

            // 添加有效数据到批次
            batchResults.push(...item.json.ET_OUTPUT);
        }

        // 存储当前批次结果
        if (batchResults.length > 0) {
            outputBatches.push({
                batchIndex: Math.floor(i / batchSize) + 1,
                data: batchResults
            });
        }

        // 可选: 每处理完一批就释放内存
        batchResults = null;
    }

    // 准备最终输出
    if (allSuccess) {
        // 返回成功和所有批次数据
        return [{
            json: {
                tag: 0,
                batchCount: outputBatches.length,
                batches: outputBatches,
                totalProcessed: processedCount
            }
        }];
    } else {
        // 返回失败和错误详情
        return [{
            json: {
                tag: 1,
                errorCount: errorMessages.length,
                errors: errorMessages.slice(0, 10), // 只返回前10个错误
                batchesProcessed: outputBatches.length,
                totalProcessed: processedCount
            }
        }];
    }
} catch (error) {
    return [{
        json: {
            tag: 2,
            error: error.message,
            processedUpTo: processedCount
        }
    }];
}
